const raw = $input.first().json;
let time = '', message = 'Reminder!';
try {
  const p = JSON.parse(raw.query || '{}');
  time = p.time || '';
  message = p.message || 'Reminder!';
} catch(e) {
  time = raw.time || '';
  message = raw.message || 'Reminder!';
}

// Parse ISO 8601 time
const remindAt = time || new Date().toISOString();

// Get user context from the calling workflow
const chatId = raw.chatId || raw.chat_id || '{{TELEGRAM_CHAT_ID}}';
const userId = raw.userId || raw.user_id || 'unknown';

// Insert into reminders table via PostgREST
const response = await helpers.httpRequest({
  method: 'POST',
  url: '{{SUPABASE_URL}}/reminders',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer {{SUPABASE_SERVICE_KEY}}',
    'Prefer': 'return=representation'
  },
  body: {
    user_id: userId,
    chat_id: String(chatId),
    message: message,
    remind_at: remindAt
  },
  json: true
});

return [{ json: { success: true, message: `Reminder set for ${remindAt}: ${message}`, id: response[0]?.id } }];
